changeSet.sql:
IF EXISTS (SELECT * FROM sys.foreign_keys WHERE name = 'fk_edges_source_node')
ALTER TABLE dbo.Edges DROP CONSTRAINT fk_edges_source_node;

IF EXISTS (SELECT * FROM sys.foreign_keys WHERE name = 'fk_edges_target_node')
ALTER TABLE dbo.Edges DROP CONSTRAINT fk_edges_target_node;

ALTER TABLE dbo.Edges ADD CONSTRAINT fk_edges_source_node_cascade
    FOREIGN KEY (source_node_id) REFERENCES dbo.Nodes(node_id) ON DELETE CASCADE;

ALTER TABLE dbo.Edges ADD CONSTRAINT fk_edges_target_node_no_action
    FOREIGN KEY (target_node_id) REFERENCES dbo.Nodes(node_id) ON DELETE NO ACTION;

rollback.sql:
ALTER TABLE dbo.Edges DROP CONSTRAINT fk_edges_source_node_cascade;
ALTER TABLE dbo.Edges DROP CONSTRAINT fk_edges_target_node_no_action;

ALTER TABLE dbo.Edges ADD CONSTRAINT fk_edges_source_node
FOREIGN KEY (source_node_id) REFERENCES dbo.Nodes(node_id);

ALTER TABLE dbo.Edges ADD CONSTRAINT fk_edges_target_node
FOREIGN KEY (target_node_id) REFERENCES dbo.Nodes(node_id);
